require 'rake'
require 'fileutils'

task :backup do
  backup_name = ENV['BACKUP'] || "default"
  backup_path = ENV['PATH'] || "/tmp/backups/"

  FileUtils.mkdir(backup_path) unless File.exists?(backup_path)

  puts "Creating backup #{backup_name}"

  tar_command = "tar -czf #{backup_path}#{backup_name}.tgz /home"
  puts %x{#{tar_command}}
end